#include <stdio.h>
#include <stdlib.h>
#define MAX 500
int max(int a, int b) { return a > b ? a : b; }
int dp[MAX][MAX];
int grid[MAX][MAX];
int m, n;
int solve(int i, int j) {
    if (dp[i][j] != -1) return dp[i][j];
    int ans = 1;
    for (int k = j + 1; k < n; k++) {
        if (grid[i][k] >= grid[i][j]) {
            ans = max(ans, 1 + solve(i, k));
        }
    }
    for (int k = i + 1; k < m; k++) {
        if (grid[k][j] <= grid[i][j]) {
            ans = max(ans, 1 + solve(k, j));
        }
    }
    return dp[i][j] = ans;
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        scanf("%d %d", &m, &n);
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                scanf("%d", &grid[i][j]);
                dp[i][j] = -1;
            }
        }
        int ans = 0;
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                ans = max(ans, solve(i, j));
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

