import java.util.Scanner;
public class Main {
    static final int MAX = 500;
    static int[][] dp = new int[MAX][MAX];
    static int[][] grid = new int[MAX][MAX];
    static int m, n;
    static int solve(int i, int j) {
        if (dp[i][j] != -1) return dp[i][j];
        int ans = 1;
        for (int k = j + 1; k < n; k++) {
            if (grid[i][k] >= grid[i][j]) {
                ans = Math.max(ans, 1 + solve(i, k));
            }
        }
        for (int k = i + 1; k < m; k++) {
            if (grid[k][j] <= grid[i][j]) {
                ans = Math.max(ans, 1 + solve(k, j));
            }
        }
        return dp[i][j] = ans;
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            m = sc.nextInt();
            n = sc.nextInt();
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    grid[i][j] = sc.nextInt();
                    dp[i][j] = -1;
                }
            }
            int ans = 0;
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    ans = Math.max(ans, solve(i, j));
                }
            }
            System.out.println(ans);
        }
    }
}

