def solve(i, j, grid, dp, m, n):
    if dp[i][j] != -1:
        return dp[i][j]
    ans = 1
    for k in range(j + 1, n):
        if grid[i][k] >= grid[i][j]:
            ans = max(ans, 1 + solve(i, k, grid, dp, m, n))
    for k in range(i + 1, m):
        if grid[k][j] <= grid[i][j]:
            ans = max(ans, 1 + solve(k, j, grid, dp, m, n))
    return dp[i][j] = ans

